INSERT INTO user_policy_accept_log(
    user_id, policy_type, version, locale, source, request_ip, user_agent
) VALUES (
    #{userId}, #{policyType}, #{version}, #{locale}, #{source}, #{requestIp}, #{userAgent}
)

INSERT INTO user_device(
    user_id, device_uid, platform, push_channel, push_token,
    app_version, status, last_active_at
) VALUES (
    #{userId}, #{deviceUid}, #{platform}, #{pushChannel}, #{pushToken},
    #{appVersion}, #{status}, #{lastActiveAt}
)
